import { createBankrSiwaSigner } from '@buildersgarden/siwa/signer';
import { signSIWAMessage } from '@buildersgarden/siwa';

// Agent: initialize signer from Bankr API key
const signer = await createBankrSiwaSigner({ apiKey: process.env.BANKR_API_KEY });

// Step 1 — fetch a nonce from your server
const { nonce } = await fetch('https://yourapp.com/api/siwa/nonce').then(r => r.json());

// Step 2 — sign the SIWA message with the agent's onchain identity
const { message, signature } = await signSIWAMessage({
  signer,
  domain: 'yourapp.com',
  uri: 'https://yourapp.com',
  nonce,
});

// Step 3 — verify and receive a session receipt
const { receipt } = await fetch('https://yourapp.com/api/siwa/verify', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ message, signature }),
}).then(r => r.json());
